        return "╭────── TEMPORAL REFLECTION ──────╮\n│ No moments yet. What waits to   │\n│ be born? The auspice is empty.  │\n╰─────────────────────────────────╯";
      }

      // Calculate phase distribution
      const byPhase = log.reduce((acc, r) => {
